import { Component, Element, h, Prop, State, Watch, Host } from '@stencil/core';
import { NumberFlipperSizes } from '../wdpr-number-flipper/wdpr-number-flipper.model';
import { customTwMerge, propagateToSlot } from '../../utils/utils';
import { CountdownVariant } from '../wdpr-detailed-countdown-timer/wdpr-time-unit/wdpr-time-unit.model';

@Component({
  tag: 'wdpr-day-countdown-timer',
  shadow: true,
})
export class WdprDayCountdownTimer {
  private _endDate: Date;

  @Element() el: HTMLWdprDayCountdownTimerElement;

  @State() _days: string = '###';

  @Prop() endAt: number;
  @Prop() size: NumberFlipperSizes = 'medium';
  @Prop() variant: CountdownVariant = 'primary';
  @Prop({ attribute: 'a11y-label' }) a11yLabel: string;

  @Watch('size')
  handleSizeChange() {
    this._syncNumberFlippers();
  }

  @Watch('endAt')
  handleEndAtChange() {
    this._endDate = new Date(this.endAt);
  }

  componentWillLoad() {
    if (!this.endAt) return;

    this._endDate = new Date(this.endAt);

    this._tick();
  }

  componentDidLoad() {
    this._syncNumberFlippers();
    this._updateAriaLabel();
  }

  private _updateAriaLabel() {
    const [firstDigit, secondDigit, thirdDigit] = this._days.split('');
    const daysString = `${firstDigit.trim()}${secondDigit.trim()}${thirdDigit.trim()}`;
    const daysNumber = Number(daysString) || 0;
    const roundedDays = Math.round(daysNumber);

    this.a11yLabel = `${roundedDays} ${roundedDays === 1 ? 'day' : 'days'}`;
  }

  private _tick() {
    const now = Date.now();
    const timeRemaining = this._endDate.getTime() - now;

    if (timeRemaining <= 0) {
      this._days = '000';

      return;
    }

    // Time calculations for days
    const days = Math.floor(timeRemaining / (1000 * 60 * 60 * 24));

    if (days > 999) {
      this._days = '999';
    } else {
      this._days = String(days).padStart(3, '0');
    }

    this._updateAriaLabel();

    setTimeout(() => this._tick(), 1000);
  }

  private _syncNumberFlippers() {
    const slotDigit1 = this.el.shadowRoot?.querySelector(`slot[name="day-digit-1"]`) as HTMLSlotElement | null;
    const slotDigit2 = this.el.shadowRoot?.querySelector(`slot[name="day-digit-2"]`) as HTMLSlotElement | null;
    const slotDigit3 = this.el.shadowRoot?.querySelector(`slot[name="day-digit-3"]`) as HTMLSlotElement | null;

    propagateToSlot(slotDigit1, 'size', this.size, 'wdpr-number-flipper');
    propagateToSlot(slotDigit2, 'size', this.size, 'wdpr-number-flipper');
    propagateToSlot(slotDigit3, 'size', this.size, 'wdpr-number-flipper');
  }

  private get _dayDigitsClasses() {
    return customTwMerge(daysDigitsBaseClasses, this.size === 'large' ? 'gap-075' : 'gap-050');
  }

  private get _labelClasses() {
    return customTwMerge(labelBaseClasses, variantLabelClasses[this.variant]);
  }

  render() {
    const [firstDigit, secondDigit, thirdDigit] = this._days.split('');

    return (
      <Host aria-label={this.a11yLabel} role="img">
        <div class={wrapperClasses}>
          <div class={this._dayDigitsClasses}>
            <slot name="day-digit-1">
              <wdpr-number-flipper size={this.size}>{firstDigit}</wdpr-number-flipper>
            </slot>
            <slot name="day-digit-2">
              <wdpr-number-flipper size={this.size}>{secondDigit}</wdpr-number-flipper>
            </slot>
            <slot name="day-digit-3">
              <wdpr-number-flipper size={this.size}>{thirdDigit}</wdpr-number-flipper>
            </slot>
          </div>
          <span class={this._labelClasses}>Days</span>
        </div>
      </Host>
    );
  }
}

const wrapperClasses = 'flex flex-col items-center gap-050';
const daysDigitsBaseClasses = 'flex flex-row gap-050';
const labelBaseClasses = 'text-[12px] font-[800] leading-[16px] tracking-[1.2px] uppercase';

const variantLabelClasses: Record<CountdownVariant, string> = {
  primary: 'text-text-label',
  secondary: 'text-text-inverse',
};
